appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    // --- Resolve the report object regardless of how it's bound ---
    // Your binding is: { data: JSON.parse(Query1.data.fileData) }
    // so the report lives at model.data. Fall back gracefully.
    const root = model || {};
    const report = root.data && root.data.findings ? root.data : root.findings ? root : root.data || {};
    const totals = report.totals || {};
    const inventory = report.inventory || {};
    const findings = Array.isArray(report.findings) ? report.findings : [];
    const gap = report.honest_gap || null;
    const reposScanned = report.repos_scanned || 0;
    const reposUsingAI = (inventory.repos_using_ai || []).length;
    const totalFindings = totals.findings != null ? totals.findings : findings.length;

    // --- Tally categories / patterns ---
    let weightPulls = 0; // remote model loads (from_pretrained)
    let mlDeps = 0; // declared AI/ML dependencies
    const sevCount = {}; // severity -> count
    findings.forEach(f => {
      const cat = f.category || '';
      if (cat === 'hf_import' || f.metadata && f.metadata.pattern === 'from_pretrained') weightPulls++;
      if (cat === 'ml_dependency' || f.metadata && f.metadata.dependency) mlDeps++;
      const s = (f.severity || 'unknown').toLowerCase();
      sevCount[s] = (sevCount[s] || 0) + 1;
    });
    const worstSeverity = sevCount.critical ? 'critical' : sevCount.high ? 'high' : sevCount.medium ? 'medium' : sevCount.low ? 'low' : 'none';

    // --- Composite Exposure Index (0–100) ---
    // Honest weighting: this is a discovery/inventory scan. The footprint is broad,
    // but every finding here is low severity — so severity contributes little, and
    // the index reflects surface area (shadow usage + remote pulls + blind spots)
    // rather than acute risk. Severity dominates only when high/critical findings exist.
    const aiFootprint = reposScanned ? reposUsingAI / reposScanned * 20 : 0; // max 20
    const pullPenalty = Math.min(30, weightPulls * 0.5); // remote weight loading surface, capped
    const depPenalty = mlDeps * 3;
    const gapPenalty = gap && gap.status === 'not_covered' ? 12 : 0;
    const sevPenalty = (sevCount.critical || 0) * 20 + (sevCount.high || 0) * 10 + (sevCount.medium || 0) * 4 + (sevCount.low || 0) * 0.2;
    const indexScore = Math.round(Math.min(100, aiFootprint + pullPenalty + depPenalty + gapPenalty + sevPenalty));

    // --- Header ---
    if (report.scan_name) {
      document.getElementById('scan-title').innerText = 'Shadow AI Discovery — ' + report.scan_name;
    }
    const surfaces = (report.surfaces_run || []).join(', ') || '—';
    document.getElementById('scan-subtitle').innerText = `Surfaces scanned: ${surfaces}. Inventory of undeclared AI usage, remote model-weight loading, and coverage gaps.`;

    // --- KPI cards ---
    const idxEl = document.getElementById('kpi-exposure');
    idxEl.innerText = `${indexScore}/100`;
    idxEl.style.color = indexScore > 75 ? 'var(--critical)' : indexScore > 40 ? 'var(--warning)' : 'var(--safe)';
    document.getElementById('kpi-exposure-sub').innerText = indexScore > 75 ? 'high exposure' : indexScore > 40 ? 'moderate exposure' : 'low exposure';
    document.getElementById('kpi-findings').innerText = totalFindings;
    document.getElementById('kpi-findings-sub').innerText = `all severity: ${worstSeverity}`;
    document.getElementById('kpi-repos').innerText = `${reposUsingAI}/${reposScanned}`;
    document.getElementById('kpi-repos-sub').innerText = 'repos use AI';
    document.getElementById('kpi-pulls').innerText = weightPulls;
    document.getElementById('kpi-pulls-sub').innerText = 'remote from_pretrained';

    // --- Model family footprint (scan evidence text) ---
    const families = [{
      key: 'bert',
      label: 'BERT',
      match: e => /\bbert/.test(e) && !/distilbert|squeezebert/.test(e)
    }, {
      key: 'distilbert',
      label: 'DistilBERT',
      match: e => /distilbert/.test(e)
    }, {
      key: 'squeezebert',
      label: 'SqueezeBERT',
      match: e => /squeezebert/.test(e)
    }, {
      key: 'gpt2',
      label: 'GPT-2',
      match: e => /gpt-?2/.test(e)
    }, {
      key: 'wav2vec2',
      label: 'Wav2Vec2',
      match: e => /wav2vec2/.test(e)
    }, {
      key: 'transformers',
      label: 'transformers',
      match: e => /transformers==/.test(e)
    }];
    const famCounts = {};
    findings.forEach(f => {
      const e = (f.evidence || '').toLowerCase();
      for (const fam of families) {
        if (fam.match(e)) {
          famCounts[fam.label] = (famCounts[fam.label] || 0) + 1;
          break;
        }
      }
    });
    renderBars('family-bars', famCounts, '#9b59b6');

    // --- Hotspot directories (repo + top-level folder) ---
    const dirCounts = {};
    findings.forEach(f => {
      const path = f.file_path || '';
      const repoShort = (f.repo || '').split('/').pop();
      const top = path.indexOf('/') > -1 ? path.split('/')[0] : path;
      const key = `${repoShort}/${top}`;
      dirCounts[key] = (dirCounts[key] || 0) + 1;
    });
    renderBars('dir-bars', dirCounts, '#e67e22');

    // --- Key findings (executive, derived from real data) ---
    const list = document.getElementById('findings-list');
    list.innerHTML = '';
    const items = [];
    if (reposUsingAI > 0) {
      items.push(`<strong>Shadow AI footprint:</strong> ${reposUsingAI} of ${reposScanned} scanned repositories pull AI models or libraries — ${(inventory.repos_using_ai || []).map(r => `<code>${r}</code>`).join(', ')}.`);
    }
    if (weightPulls > 0) {
      items.push(`<strong>Remote weight loading:</strong> ${weightPulls} <code>from_pretrained</code> calls fetch model weights from the Hugging Face Hub at runtime. Unpinned references can shift under you and expand the supply-chain surface.`);
    }
    if (mlDeps > 0) {
      const dep = Object.keys(inventory.ai_dependency_chain || {}).join(', ') || 'AI/ML packages';
      items.push(`<strong>Declared AI dependency:</strong> ${mlDeps} pinned AI/ML dependency detected (<code>${dep}</code>). Track it in your SBOM and watch for CVEs against the pinned version.`);
    }
    // single-actor concentration
    const actors = [...new Set(findings.map(f => f.actor).filter(Boolean))];
    if (actors.length === 1 && findings.length > 1) {
      items.push(`<strong>Concentrated ownership:</strong> all ${findings.length} findings trace to a single account (<code>${actors[0]}</code>) — a governance and bus-factor consideration for AI assets.`);
    }
    if (gap && gap.status === 'not_covered') {
      items.push(`<strong>Known blind spot:</strong> the <code>${gap.surface}</code> surface is not covered by this scan (see Coverage Gap below).`);
    }
    if (items.length === 0) {
      list.innerHTML = '<li style="color: var(--safe);">No AI usage or boundary issues detected in scanned surfaces.</li>';
    } else {
      items.forEach(html => {
        const li = document.createElement('li');
        li.innerHTML = html;
        list.appendChild(li);
      });
    }

    // --- Coverage gap callout ---
    const gapBox = document.getElementById('gap-container');
    if (gap) {
      gapBox.style.display = 'block';
      document.getElementById('gap-title').innerText = `Coverage Gap — ${gap.surface} (${(gap.status || '').replace(/_/g, ' ')})`;
      document.getElementById('gap-summary').innerText = gap.summary || '';
      document.getElementById('gap-forward').innerText = gap.path_forward || '';
    } else {
      gapBox.style.display = 'none';
    }

    // --- File hotspots table ---
    const tbody = document.getElementById('hotspot-table-body');
    tbody.innerHTML = '';
    const byFile = {};
    findings.forEach(f => {
      const k = f.file_path || '(unknown)';
      if (!byFile[k]) byFile[k] = {
        count: 0,
        repo: f.repo || '',
        category: f.category || '',
        severity: f.severity || 'low'
      };
      byFile[k].count++;
    });
    const rows = Object.entries(byFile).map(([file, v]) => ({
      file,
      ...v
    })).sort((a, b) => b.count - a.count);
    const badgeFor = sev => {
      switch ((sev || '').toLowerCase()) {
        case 'critical':
          return 'badge-critical';
        case 'high':
          return 'badge-warning';
        case 'medium':
          return 'badge-warning';
        case 'low':
          return 'badge-low';
        default:
          return 'badge-safe';
      }
    };
    const actionFor = cat => cat === 'ml_dependency' ? 'Pin & track in SBOM; monitor CVEs and upgrade the version.' : 'Pin model revisions (commit hash) and load from an internal mirror/registry.';
    if (rows.length === 0) {
      tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;">No file-level findings.</td></tr>';
    } else {
      rows.forEach(r => {
        const tr = document.createElement('tr');
        const fileName = r.file.split('/').pop();
        tr.innerHTML = `<td><strong>${fileName}</strong><br><span style="color:var(--muted);font-size:.85rem;">${r.file}</span></td>` + `<td><code>${(r.repo || '').split('/').pop()}</code></td>` + `<td>${r.count}</td>` + `<td><span class="badge ${badgeFor(r.severity)}">${(r.severity || 'low').toUpperCase()}</span></td>` + `<td>${actionFor(r.category)}</td>`;
        tbody.appendChild(tr);
      });
    }
  });

  // Helper: render a set of {label: count} as horizontal bars (sorted desc)
  function renderBars(containerId, counts, color) {
    const el = document.getElementById(containerId);
    const entries = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    if (entries.length === 0) {
      el.innerHTML = '<div class="bar-empty">No data.</div>';
      return;
    }
    const max = Math.max(...entries.map(e => e[1]));
    el.innerHTML = '';
    entries.forEach(([label, count]) => {
      const pct = Math.max(6, Math.round(count / max * 100));
      const row = document.createElement('div');
      row.className = 'bar-row';
      row.innerHTML = `<div class="bar-label" title="${label}">${label}</div>` + `<div class="bar-track"><div class="bar-fill" style="width:${pct}%;background:${color};"></div></div>` + `<div class="bar-count">${count}</div>`;
      el.appendChild(row);
    });
  }
});

